            line-height: 1.6;
        }
        .container {
            display: flex;
            flex-direction: column;
            gap: 20px;
        }
        .graph-input {
            display: grid;
            grid-template-columns: repeat(4, 1fr);
            gap: 5px;
            margin-bottom: 20px;
        }
        .graph-input input {
            width: 50px;
            padding: 5px;
            text-align: center;
        }
        button {
            padding: 8px 16px;
            background-color: #4CAF50;
            color: white;
            border: none;
            cursor: pointer;
            font-size: 16px;
        }
        button:hover {
            background-color: #45a049;
        }
        table {
            border-collapse: collapse;
            width: 100%;
            margin: 20px 0;
        }
        th, td {
            border: 1px solid #ddd;
            padding: 8px;
            text-align: center;
        }
        th {
            background-color: #f2f2f2;
        }
        .step {
            margin-bottom: 30px;
        }
        .step {
            font-weight: bold;
            margin-bottom: 10px;
        }
        .infinity {
            color: #999;
        }
    </style>
</head>
<body>
    <h1>Floyd-Warshall Algorithm</h1>
    <p>The Floyd-Warshall algorithm finds the shortest paths between all pairs of vertices in a weighted graph. It works for both directed and undirected graphs, and can handle negative weights (but not negative cycles).</p>

    <div class="container">
        <div>
            <h2>Input Graph</h2>
            <p>Enter the adjacency matrix (use INF for infinity/no connection):</p>
            <div id="graph-container" class="graph-input"></div>
            <div>
                <label for="size">Number of vertices:</label>
                <input type="number" id="size" min="2" max="10" value="4">
                <button onclick="createGraphInput()">Create Matrix</button>
                <button onclick="runAlgorithm()">Run Algorithm</button>
            </div>
        </div>

        <div id="result">
            <h2>Results</h2>
            <div id="steps"></div>
        </div>
    </div>

    <script>
        const INF = Infinity;

        // Sample graph (4x4 adjacency matrix)
        let sampleGraph = [
            [0, 3, INF, 5],
            [2, 0, INF, 4],
            [INF, 1, 0, INF],
            [INF, INF, 2, 0]
        ];

        // Initialize graph input
        function createGraphInput() {
            const size = parseInt(document.getElementById('size').value);
            const container = document.getElementById('graph-container');
            container.innerHTML = '';

            // Create header row
            for (let i = 0; i <= size; i++) {
                const cell = document.createElement('div');
                if (i === 0) {
                    cell.textContent = '';
                } else {
                    cell.textContent = String.fromCharCode(64 + i);
                }
                container.appendChild(cell);
            }

            // Create matrix
            for (let i = 0; i < size; i++) {
                // Row label
                const label = document.createElement('div');
                label.textContent = String.fromCharCode(65 + i);
                container.appendChild(label);

                // Cells
                for (let j = 0; j < size; j++) {
                    const input = document.createElement('input');
                    input.type = 'text';
                    input.id = `cell-${i}-${j}`;
                    input.value = (i === j) ? '0' : (sampleGraph[i] && sampleGraph[i][j] !== undefined) ? 
                                  (sampleGraph[i][j] === INF ? 'INF' : sampleGraph[i][j]) : 'INF';
                    container.appendChild(input);
                }
            }
        }

        // Parse input graph
        function getInputGraph() {
            const size = parseInt(document.getElementById('size').value);
            const graph = [];

            for (let i = 0; i < size; i++) {
                graph[i] = [];
                for (let j = 0; j < size; j++) {
                    const value = document.getElementById(`cell-${i}-${j}`).value.trim();
                    graph[i][j] = (value === 'INF') ? INF : parseInt(value);
                }
            }

            return graph;
        }

